script:
export const meta = { name: 'camiel-full-roadmap', description: 'Complete the entire Project-Camiel Godot roadmap: alpha-v0.0.2, alpha-v0.0.3, and known tech debt', phases: [{ title: 'Scout codebase' }, { title: 'Alpha v0.0.2' }, { title: 'Alpha v0.0.3' }, { title: 'Tech debt' }, { title: 'Verify & tag' }] };

const PROJECT = '/Volumes/T9/Code/projects/Project-Camiel';

phase('Scout codebase');

const scout = await agent('Thoroughly explore the Godot 4 project at ' + PROJECT + '. Read and return the FULL content of: project.godot, scenes/main.tscn, scenes/camiel.tscn, scripts/camiel_controller.gd, scripts/intro_scene.gd, scripts/tools/verify_camiel_resources.gd, scripts/tools/build_camiel_resources.gd, ALPHA_V0_0_1_NOTES.md, docs/roadmap.md, docs/project-overview.md, docs/development-log.md, docs/godot-setup.md, docs/assets-and-animations.md, export_presets.cfg, .github/workflows/ci.yml (if exists). Also run: ls -la ' + PROJECT + '/scenes/ && ls -la ' + PROJECT + '/scripts/ && ls -la ' + PROJECT + '/scripts/tools/ && ls -la ' + PROJECT + '/assets/ && ls -la ' + PROJECT + '/assets/camiel/ && ls -la ' + PROJECT + '/docs/. Return ALL output verbatim.', { label: 'scout-godot-camiel', tier: 'medium', cwd: PROJECT });

phase('Alpha v0.0.2');

const a02 = await parallel([
  () => agent('Implement Alpha v0.0.2 milestone for Project-Camiel (Godot 4 / GDScript at ' + PROJECT + '). Goal: Simple main menu with one big Start button. Create scenes/main_menu.tscn and scripts/main_menu.gd. Requirements: one large Start button centered, transitions to scenes/main.tscn on press, keyboard accessible (Enter key), child-friendly style matching existing visuals, version label "alpha v0.0.2" at bottom. Read existing scripts first: scripts/intro_scene.gd and scripts/camiel_controller.gd for style. Read project.godot for scene config. Write all new files. Return FULL content of every file created/modified.', { label: 'a02-main-menu', tier: 'medium', cwd: PROJECT }),
  () => agent('Implement audio for Alpha v0.0.2 of Project-Camiel (Godot 4 / GDScript at ' + PROJECT + '). Goal: gentle background music and soft sound effects. Tasks: 1) Create scripts/audio_manager.gd as an Autoload singleton managing: bgm (looping), sfx for collect and finish events, play_music/stop_music/play_sfx methods, Master+SFX audio buses. 2) Create assets/audio/ directory with README listing required files: bgm_ambient.ogg, sfx_collect.ogg, sfx_finish.ogg (placeholders OK). 3) The AudioStreamPlayer should persist across scene changes via Autoload. Read project.godot for autoload/bus config. Return FULL contents of all new files.', { label: 'a02-audio', tier: 'medium', cwd: PROJECT }),
  () => agent('Implement collectible for Alpha v0.0.2 of Project-Camiel (Godot 4 / GDScript at ' + PROJECT + '). Goal: one collectible object (star or biscuit). Tasks: 1) Create scripts/collectible.gd extending Area2D with idle animation, _on_body_entered checks for Camiel, triggers hide + play_sfx + collected signal. 2) Create scenes/collectible.tscn (Area2D+CollisionShape2D+Sprite2D). 3) Add one instance to scenes/main.tscn. 4) Create simple HUD showing "Stars: X" count updating on collectible.collected signal. 5) Create assets/collectibles/star.png placeholder or Godot resource. Read scripts/camiel_controller.gd and scenes/main.tscn first. Return FULL contents of all new/modified files.', { label: 'a02-collectible', tier: 'medium', cwd: PROJECT }),
  () => agent('Implement finish marker for Alpha v0.0.2 of Project-Camiel (Godot 4 / GDScript at ' + PROJECT + '). Goal: finish marker so child completes the intro. Tasks: 1) Create scripts/finish_marker.gd extending Area2D with flag sprite/AnimatedSprite2D, _on_body_entered shows "Goed zo!" message, plays sfx_finish, after 2s shows "Press Enter to play again". 2) Create scenes/finish_marker.tscn. 3) Add to scenes/main.tscn. 4) Create scripts/win_screen.gd or update intro_scene.gd for celebration UI with final star count. Read scripts/intro_scene.gd for existing UI patterns. Return FULL contents of all new/modified files.', { label: 'a02-finish-marker', tier: 'medium', cwd: PROJECT }),
]);

phase('Alpha v0.0.3');

const a03 = await parallel([
  () => agent('Implement educational micro-tasks for Alpha v0.0.3 of Project-Camiel (Godot 4 / GDScript at ' + PROJECT + '). Goals: 1) Touch the red block, 2) Find blue, 3) Count 1-2-3 objects. Tasks: 1) scripts/red_block.gd + scenes/red_block.tscn (Area2D, red RectangleShape2D, flash green on Camiel touch, play success chime). 2) scripts/blue_target.gd + scenes/blue_target.tscn (blue object slightly camouflaged, success on find/touch). 3) scripts/count_challenge.gd + scenes/count_challenge.tscn (3 spaced collectibles, counter UI Label "Count: 0", increments on touch, shows "3! Goed zo!" at 3). 4) Create scenes/lesson_1.tscn containing all three challenges. 5) Main menu should offer a "Lesson" button after intro complete. Read scripts/camiel_controller.gd and project.godot for collision layers. Return FULL contents of all new/modified files.', { label: 'a03-micro-tasks', tier: 'medium', cwd: PROJECT }),
  () => agent('Create docs/parent-teacher-notes.md for Alpha v0.0.3 of Project-Camiel (Godot 4 at ' + PROJECT + '). Content: 1) Age recommendation 3+, 2) Learning objectives per micro-task (color recognition, visual discrimination, number sense), 3) How to play guide (set pace, no punishment), 4) Classroom use (1:1 adult-child, projector whole-group, differentiation), 5) Accessibility (large touch targets, no time pressure, audio+visual feedback, high contrast), 6) Technical info (Godot 4, Windows, MIT/GPL license), 7) How to contribute (CONTRIBUTING.md), 8) Feedback via GitHub issues. Clean Markdown, friendly tone for non-technical educators. Return FULL content.', { label: 'a03-parent-notes', tier: 'small', cwd: PROJECT }),
  () => agent('Implement accessibility checks for Alpha v0.0.3 of Project-Camiel (Godot 4 / GDScript at ' + PROJECT + '). Tasks: 1) Create docs/accessibility-report.md documenting: color contrast (WCAG AA 4.5:1 normal / 3:1 large), font sizes (min 18pt body, 24pt+ buttons), touch targets (min 48x48px), motion/animation (no fast flashing), keyboard accessibility (Tab/Enter on all buttons), audio+visual feedback (not audio-only). 2) Apply fixes: ensure font sizes 24+ in scripts/main_menu.gd and intro_scene.gd, add dark ColorRect behind text labels for readability, verify keyboard focus on all Buttons. 3) Create scripts/accessibility.gd singleton with toggle_high_contrast() method. 4) In project.godot ensure window min 800x600 and stretch mode set. Read project.godot for current display settings. Return FULL contents of all new/modified files.', { label: 'a03-accessibility', tier: 'medium', cwd: PROJECT }),
]);

phase('Tech debt');

const techdebt = await parallel([
  () => agent('Implement GitHub Actions automated exports for Project-Camiel (Godot 4 at ' + PROJECT + '). Create .github/workflows/export.yml: triggers on push to main + version tags (v*.*.*), sets up Godot 4 (godot-actions), runs scripts/tools/quality_gate.py, exports Windows desktop build, uploads .exe and .zip as artifacts, on tag push creates GitHub Release. Also update docs/build-and-release.md to document the new CI/CD pipeline. Read scripts/tools/quality_gate.py and export_presets.cfg first. Return FULL contents of .github/workflows/export.yml and updated docs/build-and-release.md.', { label: 'tech-gha-exports', tier: 'medium', cwd: PROJECT }),
  () => agent('Implement code signing documentation for Project-Camiel Windows builds (Godot 4 at ' + PROJECT + '). Tasks: 1) Create docs/code-signing.md explaining: what code signing is, Windows SmartScreen, options (SignPath.io free, Digicert, SSL.com), do NOT commit real certs, environment variables needed (AUTHENTICODE_CERT_PATH, AUTHENTICODE_PASSWORD), GitHub Actions integration. 2) Create scripts/sign_build.gd documenting the signtool command to run post-export. 3) Add .gitattributes treating .exe as binary. 4) Update export.yml (or document) to skip signing if cert env vars absent (dont break build). Since no actual cert available, make it cert-ready. Return FULL contents of all new/modified files.', { label: 'tech-code-signing', tier: 'small', cwd: PROJECT }),
  () => agent('Implement title screen and version label for Project-Camiel (Godot 4 at ' + PROJECT + '). Title screen: create scenes/title_screen.tscn with game title "Camiel" in large friendly font, Camiel character sprite with idle animation playing, "Play" button leading to main menu, optional "About" button, version label "alpha-v0.0.2" bottom-right. Create scripts/title_screen.gd. Update project.godot to set scenes/title_screen.tscn as primary scene. Version label: create scenes/ui/version_label.tscn + scripts/ui/version_label.gd (extends Label, sets text to current version in _ready), add to main_menu main.tscn lesson_1.tscn and title_screen. Read project.godot for current scene entry point and scenes/main.tscn for UI patterns. Return FULL contents of all new/modified files.', { label: 'tech-title-version', tier: 'medium', cwd: PROJECT }),
]);

phase('Verify & tag');

const verify = await agent('Final verification for Project-Camiel at ' + PROJECT + ' after all other phases: 1) Read all newly created/modified files, verify GDScript syntax (extends, _ready, _process, _input), valid .tscn Godot format, correct scene entries in project.godot, updated export_presets.cfg for alpha-v0.0.2. 2) Check for: circular scene references, missing autoloads (AudioManager, Accessibility), physics layer conflicts, hardcoded paths. 3) Update docs/roadmap.md marking alpha-v0.0.2 and alpha-v0.0.3 as done with date 2026-06-05. 4) Create or update CHANGELOG.md with entries for alpha-v0.0.2 (main menu, audio manager, collectibles, finish marker), alpha-v0.0.3 (educational tasks, parent notes, accessibility), tech debt (GHA exports, code signing docs, title screen, version label). 5) Git add all new files. 6) Print organized summary of ALL files created/modified. Read docs/roadmap.md first. Return the summary and updated roadmap content.', { label: 'final-verify', tier: 'medium', cwd: PROJECT });

return {
  ok: true,
  phases: ['scout', 'alpha-v0.0.2', 'alpha-v0.0.3', 'tech-debt', 'verify'],
  scout: scout ? scout.slice(0, 500) : null,
  a02: a02.map(function(r) { return r ? r.slice(0, 300) : null; }),
  a03: a03.map(function(r) { return r ? r.slice(0, 300) : null; }),
  techdebt: techdebt.map(function(r) { return r ? r.slice(0, 300) : null; }),
  final_verify: verify,
};
